import Navbar from '../components/Navbar'
import Hero from '../components/Hero'
import BentoSlideshow from '../components/BentoSlideshow'
import ClientsCarousel from '../components/ClientsCarousel'
import ContactInfoPanel from '../components/ContactInfoPanel'
import Footer from '../components/Footer'

const projects = [
  {title: 'Commercial Building HVAC Revamp', excerpt: 'Energy-efficient HVAC design for a 12-storey building.'},
  {title: 'Data Center Cooling Optimization', excerpt: 'High-density cooling solution with redundancy.'},
  {title: 'Mixed-use Development MEP', excerpt: 'Integrated MEP systems for mixed residential and retail.'},
  {title: 'Hospital Infrastructure Upgrade', excerpt: 'Critical MEP systems for healthcare facility.'},
  {title: 'Smart Building Controls', excerpt: 'IoT-enabled mechanical and electrical systems.'},
  {title: 'Industrial Plant Retrofit', excerpt: 'Complete MEP overhaul for manufacturing.'},
  {title: 'Green Office Tower', excerpt: 'Sustainable MEP design with LEED certification.'}
]

export default function Home(){
  return (
    <div>
      <Navbar />
      <Hero title={"Mechanical • Electrical • Plumbing •"} subtitle={"Practical, sustainable MEP solutions for modern buildings."} cta={{href:'/projects', label:'Explore Projects'}} />
      <main>
        <section className="py-12">
          <div className="w-full text-center mb-8">
            <div className="flex items-center justify-center gap-3 mb-4">
              <span className="w-3 h-3 rounded-full bg-blue-500 animate-pulse inline-block" aria-hidden="true" />
              <span className="uppercase tracking-widest text-sm">PROJECT</span>
            </div>
            <h2 className="text-5xl md:text-7xl lg:text-9xl font-extrabold tracking-tight uppercase">PORTFOLIO</h2>
          </div>

          <BentoSlideshow projects={projects} />

          <ClientsCarousel />
          <ContactInfoPanel />
        </section>
      </main>
      <Footer />
    </div>
  )
}
